"""
3296. Minimum Number of Seconds to Make Mountain Height Zero
Medium
Topics
premium lock icon
Companies
Hint
You are given an integer mountainHeight denoting the height of a mountain.

You are also given an integer array workerTimes representing the work time of workers in seconds.

The workers work simultaneously to reduce the height of the mountain. For worker i:

To decrease the mountain's height by x, it takes workerTimes[i] + workerTimes[i] * 2 + ... + workerTimes[i] * x seconds. For example:
To reduce the height of the mountain by 1, it takes workerTimes[i] seconds.
To reduce the height of the mountain by 2, it takes workerTimes[i] + workerTimes[i] * 2 seconds, and so on.
Return an integer representing the minimum number of seconds required for the workers to make the height of the mountain 0.

 

Example 1:

Input: mountainHeight = 4, workerTimes = [2,1,1]

Output: 3

Explanation:

One way the height of the mountain can be reduced to 0 is:

Worker 0 reduces the height by 1, taking workerTimes[0] = 2 seconds.
Worker 1 reduces the height by 2, taking workerTimes[1] + workerTimes[1] * 2 = 3 seconds.
Worker 2 reduces the height by 1, taking workerTimes[2] = 1 second.
Since they work simultaneously, the minimum time needed is max(2, 3, 1) = 3 seconds.

Example 2:

Input: mountainHeight = 10, workerTimes = [3,2,2,4]

Output: 12

Explanation:

Worker 0 reduces the height by 2, taking workerTimes[0] + workerTimes[0] * 2 = 9 seconds.
Worker 1 reduces the height by 3, taking workerTimes[1] + workerTimes[1] * 2 + workerTimes[1] * 3 = 12 seconds.
Worker 2 reduces the height by 3, taking workerTimes[2] + workerTimes[2] * 2 + workerTimes[2] * 3 = 12 seconds.
Worker 3 reduces the height by 2, taking workerTimes[3] + workerTimes[3] * 2 = 12 seconds.
The number of seconds needed is max(9, 12, 12, 12) = 12 seconds.

Example 3:

Input: mountainHeight = 5, workerTimes = [1]

Output: 15

Explanation:

There is only one worker in this example, so the answer is workerTimes[0] + workerTimes[0] * 2 + workerTimes[0] * 3 + workerTimes[0] * 4 + workerTimes[0] * 5 = 15.

 

Constraints:

1 <= mountainHeight <= 105
1 <= workerTimes.length <= 104
1 <= workerTimes[i] <= 106
"""
import math
from math import sqrt
from math import ceil
from math import floor
class Solution:
    def minNumberOfSeconds(self, mountainHeight: int, workerTimes: List[int]) -> int:
        def work_time(worker, times):
            time = 0
            for n in range(times):
                time += worker * (n+1)
            return time
        num_work = len(workerTimes)
        print("lenght = "+str(num_work))
        currentHeight = mountainHeight
        counterWork = 0
        
        #while currentHeight>=num_work:
        #    counterWork += 1
        #    currentHeight -= num_work
 
        counterWork = [counterWork]*num_work
        #currentTime = [work_time(workerTimes[i], counterWork[i]) for i in range(num_work)]
        currentTime = [0]*num_work
        #print("currentTime = "+ str(currentTime))
        #print(counterWork)
        #print("currentHeight = " + str(currentHeight))

        if num_work==1:
            while mountainHeight > 0:
                mountainHeight -= 1
                counterWork[0] += 1
            return work_time(workerTimes[0], counterWork[0])
        
        elif mountainHeight%num_work == 0:
            isEqual = True
            for x in range(1, num_work):
                if workerTimes[x] != workerTimes[x-1]:
                   isEqual = False
                   break
            if isEqual:
                return work_time(max(workerTimes), mountainHeight//num_work)
        
        while currentHeight > 0:
            next_fast = [work_time(workerTimes[i], counterWork[i]+1) for i in range(num_work)]
            fast_worker = min(next_fast)
            fast_worker_index = next_fast.index(fast_worker)
            counterWork[fast_worker_index] += 1
            currentTime[fast_worker_index] = next_fast[fast_worker_index]
            currentHeight -= 1
            #print("currentTime = "+ str(currentTime))
            #print("currentHeight = " + str(currentHeight))
        
        
        return max(currentTime)

class Solution:
    def minNumberOfSeconds(self, mountainHeight: int, workerTimes: List[int]) -> int:
        def can_finish_in(time_limit: int) -> bool:
            reduced = 0

            for wt in workerTimes:
                left, right = 0, mountainHeight
                while left <= right:
                    mid = (left + right) // 2
                    needed = wt * mid * (mid + 1) // 2

                    if needed <= time_limit:
                        left = mid + 1
                    else:
                        right = mid - 1

                reduced += right
                if reduced >= mountainHeight:
                    return True

            return False

        left = 0
        right = min(workerTimes) * mountainHeight * (mountainHeight + 1) // 2

        while left < right:
            mid = (left + right) // 2
            if can_finish_in(mid):
                right = mid
            else:
                left = mid + 1

        return left
class Solution:
    def minNumberOfSeconds(self, mountainHeight: int, workerTimes: list[int]) -> int:
        def check(max_time):
            h = 0

            for t in workerTimes:
                h += int((-1 + sqrt(1 + 8 * max_time / t)) / 2)

            return h >= mountainHeight

        mx = max(workerTimes)
        lo, hi = 1, (1 + mountainHeight) * mountainHeight * mx

        while lo < hi:
            mi = (lo + hi) // 2

            if check(mi):
                hi = mi
            else:
                lo = mi + 1

        return lo
    
class Solution:
    def minNumberOfSeconds(self, H: int, arr: List[int]) -> int:
        S = sum(arr)
        N = len(arr)
        V = ceil(H / N)
        start, end = 1, V * (V + 1) * max(arr) // 2
        while start < end:
            mid = (start + end) // 2
            W = 0
            for T in arr:
                W += floor(sqrt(2 * mid / T + 0.25) - 0.5)
            if W >= H:
                end = mid
            else:
                start = mid + 1
        return start 
    
